import{_ as i,o as s,c as t,ao as a}from"./chunks/framework.t06IGxWj.js";const k=JSON.parse('{"title":"Key concepts","description":"","frontmatter":{},"headers":[],"relativePath":"concepts.md","filePath":"concepts.md","lastUpdated":null}'),n={name:"concepts.md"};function o(l,e,p,h,r,c){return s(),t("div",null,[...e[0]||(e[0]=[a(`<h1 id="Key-concepts" tabindex="-1">Key concepts <a class="header-anchor" href="#Key-concepts" aria-label="Permalink to &quot;Key concepts {#Key-concepts}&quot;">​</a></h1><p>StrictMode&#39;s guarantees enforce properties that Julia performance relies on. This page explains what those properties are and why they matter — useful background before the <a href="./guarantees">Guarantees</a> reference.</p><h2 id="Type-stability" tabindex="-1">Type stability <a class="header-anchor" href="#Type-stability" aria-label="Permalink to &quot;Type stability {#Type-stability}&quot;">​</a></h2><p>A function is <strong>type-stable</strong> when the compiler can determine the return type from the argument types alone, without running the function. With a known concrete return type, the compiler generates tight machine code and can chain optimizations across calls.</p><p><strong>Type instability</strong> produces a <code>Union</code> or <code>Any</code> return. Every downstream operation then needs to check the type at runtime before it can do anything useful:</p><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">function</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> pick</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(items, i)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    items[i]          </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># items = (1, 2.0, &quot;three&quot;) → return is Union{Int64,Float64,String}</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">end</span></span></code></pre></div><p>The compiler can&#39;t predict which branch will run, so downstream code pays a dispatch tax on every use of the result. <code>@assert_typestable</code> and <code>@strict</code> catch this.</p><h2 id="Boxing" tabindex="-1">Boxing <a class="header-anchor" href="#Boxing" aria-label="Permalink to &quot;Boxing {#Boxing}&quot;">​</a></h2><p><strong>Boxing</strong> is what happens when the compiler can&#39;t eliminate a Union: it wraps the value in a heap-allocated container so it can be passed around as an opaque object. Unboxing later costs a heap lookup and a runtime type-check per value.</p><p>In a tight numeric loop, the difference between boxed and unboxed is often 100× or more. The most common cause is indexing a heterogeneous tuple with a runtime index:</p><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">t </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1.0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">2</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;three&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">for</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> i </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">in</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">3</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    x </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> t[i]    </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># x is boxed — the compiler doesn&#39;t know which element type it gets</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">end</span></span></code></pre></div><p>The fix is <code>@unroll</code>, which replaces the runtime index with compile-time literals:</p><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">@unroll</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> for</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> i </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">in</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">3</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    x </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> t[i]    </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># expands to t[1], t[2], t[3] — each a known concrete type</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">end</span></span></code></pre></div><p><code>@assert_noboxing</code> and <code>@assert_noalloc</code> catch boxing. <code>@explain</code> identifies which access is the source.</p><h2 id="Dynamic-dispatch" tabindex="-1">Dynamic dispatch <a class="header-anchor" href="#Dynamic-dispatch" aria-label="Permalink to &quot;Dynamic dispatch {#Dynamic-dispatch}&quot;">​</a></h2><p><strong>Dynamic dispatch</strong> is a function call resolved at runtime instead of compile time. It happens when the compiler doesn&#39;t know the concrete type of the receiver, so it can&#39;t select the method at compile time and must look it up during execution.</p><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">function</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> apply</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(f, x)</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    f</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(x)    </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># if f&#39;s concrete type is unknown, every call pays a table lookup</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">end</span></span></code></pre></div><p>In hot loops, even one dynamic dispatch per iteration can dominate. Type-unstable code usually triggers it: once a value&#39;s type is a Union, everything downstream dispatches dynamically. <code>@assert_noboxing</code> catches it because the JIT-level evidence is the same boxing pattern.</p><h2 id="SIMD-vectorization" tabindex="-1">SIMD vectorization <a class="header-anchor" href="#SIMD-vectorization" aria-label="Permalink to &quot;SIMD vectorization {#SIMD-vectorization}&quot;">​</a></h2><p>Modern CPUs process 4–16 floating-point values per instruction (AVX-512: 8 doubles at once). <strong>SIMD vectorization</strong> — Single Instruction, Multiple Data — is the compiler generating those instructions automatically for loops over contiguous data.</p><p>Things that block it: data-dependent branches, non-sequential memory, function calls the compiler can&#39;t inline, and type instability. A loop that looks vectorized often isn&#39;t.</p><p><code>@assert_vectorized</code> checks that the compiled output actually contains vector instructions. <code>kernel_report</code> explains <em>why</em> a vectorized kernel is still slow — arithmetic intensity, alignment, register pressure.</p><h2 id="How-they-interact" tabindex="-1">How they interact <a class="header-anchor" href="#How-they-interact" aria-label="Permalink to &quot;How they interact {#How-they-interact}&quot;">​</a></h2><p>These four issues cascade. A single root cause can trigger all of them:</p><ol><li><p>A heterogeneous tuple gets indexed at runtime → <strong>type instability</strong></p></li><li><p>The compiler can&#39;t track the type → the value is <strong>boxed</strong></p></li><li><p>Downstream operations can&#39;t select a method statically → <strong>dynamic dispatch</strong></p></li><li><p>The loop carries an opaque value → <strong>no SIMD</strong></p></li></ol><p>Fixing the root cause (often the type instability) eliminates all four. <code>@explain</code> shows which layer is the actual source, and <code>@strict</code> / <code>@kernel</code> confirm all four are resolved.</p>`,26)])])}const u=i(n,[["render",o]]);export{k as __pageData,u as default};
